import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.BZohXCq9.js";const r=JSON.parse('{"title":"安装与发布","description":"","frontmatter":{},"headers":[],"relativePath":"install.md","filePath":"install.md","lastUpdated":1775494190000}'),l={name:"install.md"};function n(h,s,p,d,o,k){return a(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="安装与发布" tabindex="-1">安装与发布 <a class="header-anchor" href="#安装与发布" aria-label="Permalink to &quot;安装与发布&quot;">​</a></h1><p>本页汇总 <code>0.2.0</code> 的安装目标、官方驱动安装方式和源码运行方式。</p><h2 id="_0-2-0-发布状态" tabindex="-1">0.2.0 发布状态 <a class="header-anchor" href="#_0-2-0-发布状态" aria-label="Permalink to &quot;0.2.0 发布状态&quot;">​</a></h2><p><code>0.2.0</code> 当前已经完成发布收口：</p><ul><li><code>0.2.0</code> 是一次明确的 breaking change</li><li>正式公开发布渠道为 <strong>PyPI</strong></li><li><strong>TestPyPI rehearsal</strong> 已完成</li><li><code>TestPyPI</code> 只用于发布链路演练，不作为日常安装源</li><li>当前仓库已切到 <code>0.2.0</code> 正式版代码</li></ul><h2 id="_0-2-0-升级说明" tabindex="-1">0.2.0 升级说明 <a class="header-anchor" href="#_0-2-0-升级说明" aria-label="Permalink to &quot;0.2.0 升级说明&quot;">​</a></h2><p><code>0.2.0</code> 的主线代码和文档都以纯 Python runtime 为准：</p><ul><li><code>modlink_sdk</code> / <code>modlink_core</code> 已不再依赖 Qt 运行时</li><li>外部 driver 不再以 <code>sig_frame</code> / <code>sig_connection_lost</code> 作为正式宿主契约</li><li><code>LoopDriver</code> 不再基于 <code>QTimer</code></li><li>如果你手头还有 <code>0.1.x</code> 的 Qt-style driver，需要按新的 SDK 契约迁移</li></ul><p>当前 UI 仍在适配期，但 backend 已经完成去 Qt 化；<code>0.2.0</code> 的发布边界是稳定采集、录制和保存，不包含回放。</p><h2 id="正式安装命令" tabindex="-1">正式安装命令 <a class="header-anchor" href="#正式安装命令" aria-label="Permalink to &quot;正式安装命令&quot;">​</a></h2><p><code>0.2.0</code> 的主安装入口是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><p>安装完成后，正式入口是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-studio</span></span></code></pre></div><p>调试入口保留为：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio</span></span></code></pre></div><h2 id="安装插件" tabindex="-1">安装插件 <a class="header-anchor" href="#安装插件" aria-label="Permalink to &quot;安装插件&quot;">​</a></h2><p>插件不通过 PyPI extras 安装。主包安装完成后使用独立插件管理命令；命令会先从 <code>ModLink-Studio-Plugins</code> 的 GitHub Pages 插件索引读取可用版本，再从该插件仓库的 GitHub Release 安装对应插件 wheel。</p><p>当前第一阶段，这个命令集主要覆盖官方驱动；后续会继续扩展成更通用的插件管理工具：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host-camera</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host-microphone</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openbci-ganglion</span></span></code></pre></div><p>如果不再需要某个插件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> host-camera</span></span></code></pre></div><p>如果想看当前环境里已经安装了哪些 ModLink 插件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --installed</span></span></code></pre></div><h2 id="从源码运行" tabindex="-1">从源码运行 <a class="header-anchor" href="#从源码运行" aria-label="Permalink to &quot;从源码运行&quot;">​</a></h2><p>如果目标是开发、联调或跟进仓库当前实现，可以直接从源码运行，而不是等待正式发布包。</p><p>前置要求：</p><ul><li>Python 3.13</li><li>Git</li><li><code>uv</code></li></ul><p>获取源码并同步环境：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/modlink-studio/ModLink-Studio.git</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ModLink-Studio</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>从仓库直接启动主宿主：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio</span></span></code></pre></div><p>如果要直接联调 QML 宿主：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink-studio-qml</span></span></code></pre></div><h2 id="独立脚手架工具" tabindex="-1">独立脚手架工具 <a class="header-anchor" href="#独立脚手架工具" aria-label="Permalink to &quot;独立脚手架工具&quot;">​</a></h2><p>driver 脚手架现在作为独立 npm 工具提供，而不是 <code>modlink-studio</code> 的运行时依赖：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @modlink-studio/plugin-scaffold</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --zh</span></span></code></pre></div><p>仓库内联调脚手架：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workspace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @modlink-studio/plugin-scaffold</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --zh</span></span></code></pre></div><p>更完整的 driver 开发说明见 <a href="/sdk">SDK 开发者指南</a>。</p><h2 id="发布前验证" tabindex="-1">发布前验证 <a class="header-anchor" href="#发布前验证" aria-label="Permalink to &quot;发布前验证&quot;">​</a></h2><p><code>0.2.0</code> 的 <strong>TestPyPI rehearsal</strong> 已完成。这一步只用于验证发布链路和安装命令，不作为普通用户安装入口。</p><p>正式发布前的检查重点包括：</p><ul><li>TestPyPI rehearsal 已完整跑通</li><li>PyPI 目标安装命令在干净环境中可用</li><li>插件安装 CLI 可从 GitHub Pages 插件索引解析兼容版本，并从 GitHub Release 获取 wheel</li><li><code>modlink-studio</code> 命令入口正常</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么文档已经写-pypi-但有时还搜不到最新版本" tabindex="-1">为什么文档已经写 PyPI，但有时还搜不到最新版本 <a class="header-anchor" href="#为什么文档已经写-pypi-但有时还搜不到最新版本" aria-label="Permalink to &quot;为什么文档已经写 PyPI，但有时还搜不到最新版本&quot;">​</a></h3><p>PyPI 项目页、镜像或本地索引有时会有短暂同步延迟。遇到这种情况时，以 PyPI 项目页和 <code>pip</code> / <code>uv pip</code> 的实际解析结果为准，稍后重试通常即可恢复正常。</p><h3 id="testpypi-是不是以后长期使用的安装源" tabindex="-1"><code>TestPyPI</code> 是不是以后长期使用的安装源 <a class="header-anchor" href="#testpypi-是不是以后长期使用的安装源" aria-label="Permalink to &quot;`TestPyPI` 是不是以后长期使用的安装源&quot;">​</a></h3><p>不是。<code>TestPyPI</code> 只用于发布前 rehearsal；公开安装入口以 PyPI 为准。</p><h3 id="已安装主应用但看不到某个插件" tabindex="-1">已安装主应用但看不到某个插件 <a class="header-anchor" href="#已安装主应用但看不到某个插件" aria-label="Permalink to &quot;已安装主应用但看不到某个插件&quot;">​</a></h3><p>主应用不会默认安装所有插件。当前第一阶段主要是官方驱动，需要显式运行 <code>modlink-plugin install &lt;plugin_id&gt;</code>；官方驱动源码与 wheel 资产已经迁移到独立仓库 <code>ModLink-Studio-Plugins</code>。</p><h3 id="系统里找不到-modlink-studio-命令" tabindex="-1">系统里找不到 <code>modlink-studio</code> 命令 <a class="header-anchor" href="#系统里找不到-modlink-studio-命令" aria-label="Permalink to &quot;系统里找不到 `modlink-studio` 命令&quot;">​</a></h3><p>先确认安装发生在当前 Python 环境中；如果只是临时验证，也可以直接使用 <code>python -m modlink_studio</code>。</p>',56)])])}const g=i(l,[["render",n]]);export{r as __pageData,g as default};
